// セルのエディターが表示されたときに実行
var datePicker = p.cell.getEditor();
if (datePicker && datePicker.datetimepicker) {
    // 表示形式を 'months' (月選択) に強制変更
    datePicker.datetimepicker('setStartView', 'months');
    // 選択できる最小単位を 'months' に設定する場合（月まで選べればOKな場合）
    datePicker.datetimepicker('setMinView', 'months');
}
